                            <div class="flex justify-center gap-2">
                                <span class="badge ${sellThroughRate >= 50 ? 'badge-success' : sellThroughRate >= 25 ? 'badge-warning' : 'badge-error'}">
                                    ${sellThroughRate >= 50 ? 'Good' : sellThroughRate >= 25 ? 'Average' : 'Poor'}
                                </span>
                            </div>
