                            <div class="flex justify-center gap-2">
                                <span class="badge ${roiRatio >= 50 ? 'badge-success' : roiRatio >= 20 ? 'badge-warning' : 'badge-error'}">
                                    ${roiRatio >= 50 ? 'Good' : roiRatio >= 20 ? 'Average' : 'Poor'}
                                </span>
                            </div>
